+/// Given a set of case values and a known range of the switch condition,
+/// determine whether the values not covered by any case (i.e., the default
+/// values) form a single contiguous interval within the known range.
+/// If so, return true and set \p Start and \p Size accordingly.
+static bool findContiguousMissingRange(SmallVectorImpl<ConstantInt *> &Cases,
+                                       const ConstantRange &CR,
+                                       APInt &Start, APInt &Size) {
+  if (CR.isEmptySet() || CR.isFullSet() || CR.isUpperWrapped())
+    return false;
+  // Sort cases descending.
+  SmallVector<ConstantInt *, 16> SortedCases(Cases.begin(), Cases.end());
+  array_pod_sort(SortedCases.begin(), SortedCases.end(),
+                 constantIntSortPredicate);
+  APInt Lower = CR.getLower();
+  APInt Upper = CR.getUpper();
+  // We'll iterate through the known range and find gaps.
+  // Since the number of cases is small, we can walk through sorted cases.
+  APInt Prev = Upper;
+  unsigned GapCount = 0;
+  APInt GapStart, GapEnd;
+  for (ConstantInt *C : SortedCases) {
+    APInt Val = C->getValue();
+    if (Val != Prev - 1) {
+      // There is a gap between Prev-1 down to Val+1 (since descending).
+      // The gap is [Val+1, Prev-1] inclusive.
+      if (GapCount == 0) {
+        GapStart = Val + 1;
+        GapEnd = Prev - 1;
+      }
+      GapCount++;
+    }
+    Prev = Val;
+  }
+  // Also check gap before the smallest case (i.e., between Lower and smallest).
+  if (!SortedCases.empty()) {
+    APInt Smallest = SortedCases.back()->getValue();
+    if (Smallest != Lower) {
+      // Gap from Lower to Smallest-1.
+      if (GapCount == 0) {
+        GapStart = Lower;
+        GapEnd = Smallest - 1;
+      }
+      GapCount++;
+    }
+  } else {
+    // No cases, the whole range is missing.
+    GapStart = Lower;
+    GapEnd = Upper - 1;
+    GapCount = 1;
+  }
+  if (GapCount != 1)
+    return false;
+  // Ensure gap is within CR.
+  if (GapStart.ult(Lower) || GapEnd.uge(Upper))
+    return false;
+  Start = GapStart;
+  Size = GapEnd - GapStart + 1;
+  return true;
+}
